#include <stdio.h>

struct Customer {
    int  account_number;
    char name[30];
    char address[50];
};

int main() {
    struct Customer c[10];
    int i;

    /* Input: Read details of 10 customers */
    for (i = 0; i < 10; i++) {
        printf("\nEnter details for Customer %d:\n", i + 1);
        printf("Account Number: ");
        scanf("%d", &c[i].account_number);
        printf("Name: ");
        scanf("%s", c[i].name);
        printf("Address: ");
        scanf("%s", c[i].address);
    }

    /* Output: Display all customer details */
    printf("\n%-10s %-20s %-30s\n", "Acc. No.", "Name", "Address");
    printf("----------------------------------------------------------\n");
    for (i = 0; i < 10; i++) {
        printf("%-10d %-20s %-30s\n",
               c[i].account_number, c[i].name, c[i].address);
    }

    return 0;
}

#include <stdio.h>

void square(int x) {
    x = x * x;   /* Only the local copy changes */
    printf("Inside function: %d\n", x);
}

int main() {
    int a = 5;
    square(a);
    printf("After function call: %d\n", a); /* Still 5 — unchanged */
    return 0;
}

#include <stdio.h>

void square(int *x) {
    *x = (*x) * (*x);   /* Changes the original through the pointer */
    printf("Inside function: %d\n", *x);
}

int main() {
    int a = 5;
    square(&a);          /* Pass address of variable a */
    printf("After function call: %d\n", a); /* Now 25 — changed */
    return 0;
}

#include <stdio.h>

int main() {
    int a[10], i, j, temp;

    /* Input: Read 10 integers */
    printf("Enter 10 integers:\n");
    for (i = 0; i < 10; i++) {
        printf("Number %d: ", i + 1);
        scanf("%d", &a[i]);
    }

    /* Bubble Sort — Ascending Order */
    for (i = 0; i < 9; i++) {
        for (j = 0; j < 9 - i; j++) {
            if (a[j] > a[j + 1]) {
                /* Swap adjacent elements */
                temp     = a[j];
                a[j]     = a[j + 1];
                a[j + 1] = temp;
            }
        }
    }

    /* Output: Display sorted array */
    printf("\nSorted Numbers (Ascending Order):\n");
    for (i = 0; i < 10; i++) {
        printf("%d ", a[i]);
    }

    return 0;
}

#include <stdio.h>

int main() {
    int marks[5], i, pass = 0, fail = 0;

    /* Input: Read marks of 5 students */
    printf("Enter marks of 5 students:\n");
    for (i = 0; i < 5; i++) {
        printf("Student %d marks: ", i + 1);
        scanf("%d", &marks[i]);
    }

    /* Process: Count pass and fail */
    for (i = 0; i < 5; i++) {
        if (marks[i] >= 40) {
            pass++;
        } else {
            fail++;
        }
    }

    /* Output: Display results */
    printf("\nTotal Students : 5");
    printf("\nPassed Students: %d", pass);
    printf("\nFailed Students: %d", fail);

    return 0;
}

#include <stdio.h>

struct player {
    char pname[30];
    char game[20];
    int  age;
    float salary;
};

int main() {
    struct player p[5];
    int i;

    /* Input: Read details for 5 players */
    for (i = 0; i < 5; i++) {
        printf("\nEnter details for Player %d:\n", i + 1);
        printf("Name   : "); scanf("%s", p[i].pname);
        printf("Game   : "); scanf("%s", p[i].game);
        printf("Age    : "); scanf("%d", &p[i].age);
        printf("Salary : "); scanf("%f", &p[i].salary);
    }

    /* Output: Display all player details */
    printf("\n%-20s %-15s %-5s %-10s\n",
           "Name", "Game", "Age", "Salary");
    printf("--------------------------------------------------\n");
    for (i = 0; i < 5; i++) {
        printf("%-20s %-15s %-5d %-10.2f\n",
               p[i].pname, p[i].game, p[i].age, p[i].salary);
    }

    return 0;
}
